mapper.select:
SELECT al.id ,al.adjuster_name ,al.submit_time ,al.security_short_name AS companyName ,al.security_code AS companyCode ,al.adjust_type ,al.adjust_mode ,al.target_pool_id ,p.pool_name AS target_pool_name ,al.audit_status FROM ip_adjust_log al INNER JOIN dict_security_type dst ON dst.security_type = al.security_type AND dst.is_deleted = 0 AND dst.category_type = 'company' LEFT JOIN ip_investment_pool p ON p.id = al.target_pool_id AND p.is_deleted = 0
al.is_deleted = 0
AND al.target_pool_id IN
#{id}
AND al.security_code LIKE CONCAT('%', #{companyCode}, '%')
AND al.security_short_name LIKE CONCAT('%', #{companyName}, '%')
AND al.submit_time >= #{adjustTimeStart}
AND al.submit_time <= CONCAT(#{adjustTimeEnd}, ' 23:59:59')
AND al.adjuster_name LIKE CONCAT('%', #{adjusterName}, '%')
AND al.adjust_mode = #{adjustMode}
AND al.audit_status = #{auditStatus}
ORDER BY al.submit_time DESC ,al.id DESC
